/**
 * MMS Database Schema
 *
 * Central export for all Drizzle schema definitions.
 * This file re-exports all tables, relations, and enums from domain-specific files.
 *
 * Domain Organization:
 * - enums.ts: PostgreSQL enum types
 * - core-fleet.ts: Depots, fleets, trains, routes, tracks
 * - users.ts: Users, roles, sessions
 * - operational-constraints.ts: Service demand, route utilization, unavailability, compatibility
 * - track-capabilities.ts: Track capabilities, PM requirements, baseline assumptions
 * - pm-management.ts: PM types, material requirements, PM schedule
 * - mileage-tracking.ts: Meter events, mileage readings
 * - component-tracking.ts: Train components, installations, component PM tracking
 * - material-management.ts: Inventory positions, material reservations
 * - manhour-planning.ts: Man-hour capacity, projections, adjustments
 * - baseline-drift.ts: Plan baselines, baseline snapshots, drift analysis
 * - scenarios.ts: Scenarios, deltas, comparisons
 * - costing.ts: Labor rates, material costs, cost baselines
 * - audit.ts: PM schedule history, audit log
 *
 * @see specs/003-database-schema.md for full schema specification
 */

// ============================================================================
// Enums
// ============================================================================
export * from './enums';

// ============================================================================
// Core Fleet Domain
// ============================================================================
export {
  depots,
  depotsRelations,
  fleets,
  fleetsRelations,
  routes,
  tracks,
  tracksRelations,
  trains,
  trainsRelations,
} from './core-fleet';

// ============================================================================
// Users & Authentication
// ============================================================================
export { roles, sessions, sessionsRelations, users, usersRelations } from './users';

// ============================================================================
// Operational Constraints (v2.1)
// ============================================================================
export {
  routeUtilizationProfiles,
  routeUtilizationProfilesRelations,
  serviceDemand,
  serviceDemandRelations,
  trainRouteCompatibility,
  trainRouteCompatibilityRelations,
  unavailabilityEvents,
  unavailabilityEventsRelations,
} from './operational-constraints';

// ============================================================================
// Track Capabilities (v2.1)
// ============================================================================
export {
  pmBaselineAssumptions,
  pmBaselineAssumptionsRelations,
  pmCapabilityRequirements,
  pmCapabilityRequirementsRelations,
  trackCapabilities,
  trackCapabilitiesRelations,
} from './track-capabilities';

// ============================================================================
// PM Management
// ============================================================================
export {
  pmMaterialRequirements,
  pmMaterialRequirementsRelations,
  pmSchedule,
  pmScheduleRelations,
  pmTypes,
  pmTypesRelations,
} from './pm-management';

// ============================================================================
// Mileage Tracking
// ============================================================================
export {
  meterEvents,
  meterEventsRelations,
  mileageReadings,
  mileageReadingsRelations,
} from './mileage-tracking';

// ============================================================================
// Component Tracking
// ============================================================================
export {
  componentInstallations,
  componentInstallationsRelations,
  componentPmTracking,
  componentPmTrackingRelations,
  trainComponents,
  trainComponentsRelations,
} from './component-tracking';

// ============================================================================
// Material Management
// ============================================================================
export {
  inventoryPositions,
  inventoryPositionsRelations,
  materialReservations,
  materialReservationsRelations,
} from './material-management';

// ============================================================================
// Man-hour Planning
// ============================================================================
export {
  manhourAdjustments,
  manhourAdjustmentsRelations,
  manhourCapacity,
  manhourCapacityRelations,
  manhourProjections,
  manhourProjectionsRelations,
} from './manhour-planning';

// ============================================================================
// Baseline & Drift
// ============================================================================
export {
  baselineMileageProjection,
  baselineMileageProjectionRelations,
  baselinePmSchedule,
  baselinePmScheduleRelations,
  driftAnalysis,
  driftAnalysisRelations,
  planBaselines,
  planBaselinesRelations,
} from './baseline-drift';

// ============================================================================
// Scenarios
// ============================================================================
export {
  scenarioComparisons,
  scenarioComparisonsRelations,
  scenarioDeltas,
  scenarioDeltasRelations,
  scenarios,
  scenariosRelations,
} from './scenarios';

// ============================================================================
// Costing
// ============================================================================
export {
  costBaselines,
  costBaselinesRelations,
  laborRates,
  laborRatesRelations,
  materialCosts,
} from './costing';

// ============================================================================
// Audit
// ============================================================================
export {
  auditLog,
  auditLogRelations,
  pmScheduleHistory,
  pmScheduleHistoryRelations,
} from './audit';

// ============================================================================
// Type Exports for Application Use
// ============================================================================
import type { InferInsertModel, InferSelectModel } from 'drizzle-orm';

// Core Fleet
import { depots, fleets, routes, tracks, trains } from './core-fleet';
export type Depot = InferSelectModel<typeof depots>;
export type NewDepot = InferInsertModel<typeof depots>;
export type Fleet = InferSelectModel<typeof fleets>;
export type NewFleet = InferInsertModel<typeof fleets>;
export type Train = InferSelectModel<typeof trains>;
export type NewTrain = InferInsertModel<typeof trains>;
export type Route = InferSelectModel<typeof routes>;
export type NewRoute = InferInsertModel<typeof routes>;
export type Track = InferSelectModel<typeof tracks>;
export type NewTrack = InferInsertModel<typeof tracks>;

// Users
import { roles, sessions, users } from './users';
export type User = InferSelectModel<typeof users>;
export type NewUser = InferInsertModel<typeof users>;
export type Role = InferSelectModel<typeof roles>;
export type NewRole = InferInsertModel<typeof roles>;
export type Session = InferSelectModel<typeof sessions>;
export type NewSession = InferInsertModel<typeof sessions>;

// Operational Constraints
import {
  routeUtilizationProfiles,
  serviceDemand,
  trainRouteCompatibility,
  unavailabilityEvents,
} from './operational-constraints';
export type ServiceDemand = InferSelectModel<typeof serviceDemand>;
export type NewServiceDemand = InferInsertModel<typeof serviceDemand>;
export type RouteUtilizationProfile = InferSelectModel<typeof routeUtilizationProfiles>;
export type NewRouteUtilizationProfile = InferInsertModel<typeof routeUtilizationProfiles>;
export type UnavailabilityEvent = InferSelectModel<typeof unavailabilityEvents>;
export type NewUnavailabilityEvent = InferInsertModel<typeof unavailabilityEvents>;
export type TrainRouteCompatibility = InferSelectModel<typeof trainRouteCompatibility>;
export type NewTrainRouteCompatibility = InferInsertModel<typeof trainRouteCompatibility>;

// Track Capabilities
import {
  pmBaselineAssumptions,
  pmCapabilityRequirements,
  trackCapabilities,
} from './track-capabilities';
export type TrackCapability = InferSelectModel<typeof trackCapabilities>;
export type NewTrackCapability = InferInsertModel<typeof trackCapabilities>;
export type PmCapabilityRequirement = InferSelectModel<typeof pmCapabilityRequirements>;
export type NewPmCapabilityRequirement = InferInsertModel<typeof pmCapabilityRequirements>;
export type PmBaselineAssumption = InferSelectModel<typeof pmBaselineAssumptions>;
export type NewPmBaselineAssumption = InferInsertModel<typeof pmBaselineAssumptions>;

// PM Management
import { pmMaterialRequirements, pmSchedule, pmTypes } from './pm-management';
export type PmType = InferSelectModel<typeof pmTypes>;
export type NewPmType = InferInsertModel<typeof pmTypes>;
export type PmMaterialRequirement = InferSelectModel<typeof pmMaterialRequirements>;
export type NewPmMaterialRequirement = InferInsertModel<typeof pmMaterialRequirements>;
export type PmScheduleRecord = InferSelectModel<typeof pmSchedule>;
export type NewPmScheduleRecord = InferInsertModel<typeof pmSchedule>;

// Mileage Tracking
import { meterEvents, mileageReadings } from './mileage-tracking';
export type MeterEvent = InferSelectModel<typeof meterEvents>;
export type NewMeterEvent = InferInsertModel<typeof meterEvents>;
export type MileageReading = InferSelectModel<typeof mileageReadings>;
export type NewMileageReading = InferInsertModel<typeof mileageReadings>;

// Component Tracking
import { componentInstallations, componentPmTracking, trainComponents } from './component-tracking';
export type TrainComponent = InferSelectModel<typeof trainComponents>;
export type NewTrainComponent = InferInsertModel<typeof trainComponents>;
export type ComponentInstallation = InferSelectModel<typeof componentInstallations>;
export type NewComponentInstallation = InferInsertModel<typeof componentInstallations>;
export type ComponentPmTracking = InferSelectModel<typeof componentPmTracking>;
export type NewComponentPmTracking = InferInsertModel<typeof componentPmTracking>;

// Material Management
import { inventoryPositions, materialReservations } from './material-management';
export type InventoryPosition = InferSelectModel<typeof inventoryPositions>;
export type NewInventoryPosition = InferInsertModel<typeof inventoryPositions>;
export type MaterialReservation = InferSelectModel<typeof materialReservations>;
export type NewMaterialReservation = InferInsertModel<typeof materialReservations>;

// Man-hour Planning
import { manhourAdjustments, manhourCapacity, manhourProjections } from './manhour-planning';
export type ManhourCapacity = InferSelectModel<typeof manhourCapacity>;
export type NewManhourCapacity = InferInsertModel<typeof manhourCapacity>;
export type ManhourProjection = InferSelectModel<typeof manhourProjections>;
export type NewManhourProjection = InferInsertModel<typeof manhourProjections>;
export type ManhourAdjustment = InferSelectModel<typeof manhourAdjustments>;
export type NewManhourAdjustment = InferInsertModel<typeof manhourAdjustments>;

// Baseline & Drift
import {
  baselineMileageProjection,
  baselinePmSchedule,
  driftAnalysis,
  planBaselines,
} from './baseline-drift';
export type PlanBaseline = InferSelectModel<typeof planBaselines>;
export type NewPlanBaseline = InferInsertModel<typeof planBaselines>;
export type BaselinePmSchedule = InferSelectModel<typeof baselinePmSchedule>;
export type NewBaselinePmSchedule = InferInsertModel<typeof baselinePmSchedule>;
export type BaselineMileageProjection = InferSelectModel<typeof baselineMileageProjection>;
export type NewBaselineMileageProjection = InferInsertModel<typeof baselineMileageProjection>;
export type DriftAnalysis = InferSelectModel<typeof driftAnalysis>;
export type NewDriftAnalysis = InferInsertModel<typeof driftAnalysis>;

// Scenarios
import { scenarioComparisons, scenarioDeltas, scenarios } from './scenarios';
export type Scenario = InferSelectModel<typeof scenarios>;
export type NewScenario = InferInsertModel<typeof scenarios>;
export type ScenarioDelta = InferSelectModel<typeof scenarioDeltas>;
export type NewScenarioDelta = InferInsertModel<typeof scenarioDeltas>;
export type ScenarioComparison = InferSelectModel<typeof scenarioComparisons>;
export type NewScenarioComparison = InferInsertModel<typeof scenarioComparisons>;

// Costing
import { costBaselines, laborRates, materialCosts } from './costing';
export type LaborRate = InferSelectModel<typeof laborRates>;
export type NewLaborRate = InferInsertModel<typeof laborRates>;
export type MaterialCost = InferSelectModel<typeof materialCosts>;
export type NewMaterialCost = InferInsertModel<typeof materialCosts>;
export type CostBaseline = InferSelectModel<typeof costBaselines>;
export type NewCostBaseline = InferInsertModel<typeof costBaselines>;

// Audit
import { auditLog, pmScheduleHistory } from './audit';
export type PmScheduleHistory = InferSelectModel<typeof pmScheduleHistory>;
export type NewPmScheduleHistory = InferInsertModel<typeof pmScheduleHistory>;
export type AuditLog = InferSelectModel<typeof auditLog>;
export type NewAuditLog = InferInsertModel<typeof auditLog>;

/**
 * MMS Core Fleet Domain Tables
 *
 * Asset master data: depots, fleets, trains, routes, and tracks.
 * These form the foundation of the fleet management system.
 *
 * @see specs/003-database-schema.md Section 3.2
 */

import { relations } from 'drizzle-orm';
import {
  boolean,
  date,
  decimal,
  index,
  integer,
  pgTable,
  text,
  timestamp,
  uniqueIndex,
  uuid,
  varchar,
} from 'drizzle-orm/pg-core';
import { fitnessStatusEnum, trackTypeEnum } from './enums';

/**
 * Depots - Maintenance facilities
 *
 * Physical locations where trains are maintained and stored.
 * Each depot has a timezone for correct scheduling calculations.
 */
export const depots = pgTable(
  'depots',
  {
    id: uuid('id').primaryKey().defaultRandom(),
    code: varchar('code', { length: 10 }).notNull().unique(),
    name: varchar('name', { length: 100 }).notNull(),
    location: varchar('location', { length: 200 }),
    timezone: varchar('timezone', { length: 50 }).default('Asia/Singapore'),
    active: boolean('active').default(true),
    createdAt: timestamp('created_at', { withTimezone: true }).defaultNow(),
    updatedAt: timestamp('updated_at', { withTimezone: true }).defaultNow(),
  },
  (table) => [uniqueIndex('idx_depots_code').on(table.code)]
);

/**
 * Fleets - Train types/manufacturers
 *
 * A fleet represents a group of similar trains from the same manufacturer.
 * PM types are defined per fleet as maintenance requirements vary by train model.
 */
export const fleets = pgTable(
  'fleets',
  {
    id: uuid('id').primaryKey().defaultRandom(),
    code: varchar('code', { length: 10 }).notNull().unique(),
    name: varchar('name', { length: 100 }).notNull(),
    manufacturer: varchar('manufacturer', { length: 100 }).notNull(),
    model: varchar('model', { length: 100 }),
    baseDepotId: uuid('base_depot_id').references(() => depots.id),
    carsPerTrain: integer('cars_per_train').default(6),
    active: boolean('active').default(true),
    createdAt: timestamp('created_at', { withTimezone: true }).defaultNow(),
    updatedAt: timestamp('updated_at', { withTimezone: true }).defaultNow(),
  },
  (table) => [uniqueIndex('idx_fleets_code').on(table.code)]
);

/**
 * Trains - Individual train assets
 *
 * Core asset in the system. Each train belongs to a fleet and accumulates mileage.
 * The fitness_status determines if the train can be scheduled for operations or maintenance.
 *
 * Key fields:
 * - current_mileage_km: Cumulative km reading
 * - target_mileage_km: Calculated target for fleet mileage balancing
 * - mileage_variance_km: Deviation from target (positive = above target)
 */
export const trains = pgTable(
  'trains',
  {
    id: uuid('id').primaryKey().defaultRandom(),
    fleetId: uuid('fleet_id')
      .notNull()
      .references(() => fleets.id),
    trainNumber: varchar('train_number', { length: 20 }).notNull().unique(),
    commissioningDate: date('commissioning_date'),
    currentMileageKm: integer('current_mileage_km').notNull().default(0),
    fitnessStatus: fitnessStatusEnum('fitness_status').default('FIT'),
    fitnessNotes: text('fitness_notes'),
    currentDepotId: uuid('current_depot_id').references(() => depots.id),
    homeDepotId: uuid('home_depot_id').references(() => depots.id),
    active: boolean('active').default(true),

    // Mileage balancing - target is calculated from fleet average
    targetMileageKm: integer('target_mileage_km'),
    // mileage_variance_km is calculated: current - target (done in queries)

    // Canvas display properties
    displayColor: varchar('display_color', { length: 7 }),
    displayOrder: integer('display_order'),

    createdAt: timestamp('created_at', { withTimezone: true }).defaultNow(),
    updatedAt: timestamp('updated_at', { withTimezone: true }).defaultNow(),
  },
  (table) => [
    index('idx_trains_fleet').on(table.fleetId),
    index('idx_trains_fitness').on(table.fitnessStatus),
    index('idx_trains_depot').on(table.currentDepotId),
  ]
);

/**
 * Routes - Operating lines/services
 *
 * A route represents a service that trains operate on.
 * Each route has expected daily mileage and train requirements.
 *
 * v2.1 additions:
 * - signaling_system, power_system: For compatibility matching
 * - tunnel_clearance_mm: Maximum vehicle width allowed
 * - allowed_fleet_ids: Which fleets can operate on this route
 */
export const routes = pgTable(
  'routes',
  {
    id: uuid('id').primaryKey().defaultRandom(),
    routeCode: varchar('route_code', { length: 20 }).notNull().unique(),
    routeName: varchar('route_name', { length: 100 }).notNull(),
    lineId: varchar('line_id', { length: 20 }),
    expectedKmPerDay: integer('expected_km_per_day').notNull(),
    requiredTrains: integer('required_trains').notNull(),

    // v2.1: Route characteristics for compatibility matching
    defaultDailyKm: integer('default_daily_km'),
    signalingSystem: varchar('signaling_system', { length: 30 }), // 'ATC', 'CBTC', 'ERTMS', 'LEGACY'
    powerSystem: varchar('power_system', { length: 30 }), // 'THIRD_RAIL_750V', 'OVERHEAD_25KV', etc.
    tunnelClearanceMm: integer('tunnel_clearance_mm'),
    platformLengthM: decimal('platform_length_m', { precision: 5, scale: 2 }),
    maxAxleLoadTonnes: decimal('max_axle_load_tonnes', { precision: 4, scale: 2 }),

    // Restrictions - stored as array of UUID strings
    allowedFleetIds: text('allowed_fleet_ids').array(),
    requiresAto: boolean('requires_ato').default(false),
    minCars: integer('min_cars'),
    maxCars: integer('max_cars'),

    active: boolean('active').default(true),
    createdAt: timestamp('created_at', { withTimezone: true }).defaultNow(),
    updatedAt: timestamp('updated_at', { withTimezone: true }).defaultNow(),
  },
  (table) => [uniqueIndex('idx_routes_code').on(table.routeCode)]
);

/**
 * Tracks - Maintenance bays
 *
 * Physical maintenance positions within a depot.
 * Each track has a type that determines what maintenance can be performed.
 * Track capabilities (pit, crane, etc.) are stored in a separate table.
 */
export const tracks = pgTable(
  'tracks',
  {
    id: uuid('id').primaryKey().defaultRandom(),
    depotId: uuid('depot_id')
      .notNull()
      .references(() => depots.id),
    trackNumber: varchar('track_number', { length: 20 }).notNull(),
    trackType: trackTypeEnum('track_type').notNull(),
    maxTrainLengthM: decimal('max_train_length_m', { precision: 5, scale: 2 }),
    hasOverheadCrane: boolean('has_overhead_crane').default(false),
    hasPitAccess: boolean('has_pit_access').default(false),

    active: boolean('active').default(true),
    createdAt: timestamp('created_at', { withTimezone: true }).defaultNow(),
  },
  (table) => [
    uniqueIndex('idx_tracks_depot_number').on(table.depotId, table.trackNumber),
    index('idx_tracks_depot_type').on(table.depotId, table.trackType),
  ]
);

